Settings_Vtiger_Edit_Js("Settings_AdvancedPermission_Edit_Js",{},{advanceFilterInstance:!1,registerAdvanceFilter:function(){this.advanceFilterInstance=Vtiger_AdvanceFilter_Js.getInstance($("#advanceFilterContainer"))},registerSubmitEvent:function(){var e=this,t=jQuery("#EditView");t.on("submit",function(i){var n=e.advanceFilterInstance.getValues();t.find("#advanced_filter").val(JSON.stringify(n))})},registerEvents:function(){this.registerAdvanceFilter(),this.registerSubmitEvent()}});